function solve(m: number, n: number, waitCost: number[][]): number {
    const pq: [number, number, number, number][] = [];
    pq.push([1, 0, 0, 0]);
    const dist = new Map<string, number>();
    dist.set("0_0_0", 1);

    while (pq.length > 0) {
        pq.sort((a, b) => a[0] - b[0]);
        const [currentCost, i, j, t] = pq.shift()!;
        const key = `${i}_${j}_${t}`;
        if (dist.has(key) && dist.get(key)! < currentCost) continue;

        if (i === m - 1 && j === n - 1) {
            return currentCost;
        }

        const nextTime = t + 1;
        if (nextTime % 2 === 1) {
            // Move right or down
            const newI = i + 1;
            const newJ = j;
            if (newI < m && newJ < n) {
                const newCost = currentCost + (newI + 1) * (newJ + 1);
                const newKey = `${newI}_${newJ}_${nextTime}`;
                if (!dist.has(newKey) || dist.get(newKey)! > newCost) {
                    dist.set(newKey, newCost);
                    pq.push([newCost, newI, newJ, nextTime]);
                }
            }

            const newI2 = i;
            const newJ2 = j + 1;
            if (newI2 < m && newJ2 < n) {
                const newCost2 = currentCost + (newI2 + 1) * (newJ2 + 1);
                const newKey2 = `${newI2}_${newJ2}_${nextTime}`;
                if (!dist.has(newKey2) || dist.get(newKey2)! > newCost2) {
                    dist.set(newKey2, newCost2);
                    pq.push([newCost2, newI2, newJ2, nextTime]);
                }
            }
        } else {
            // Wait
            const newCost = currentCost + waitCost[i][j];
            const newKey = `${i}_${j}_${nextTime}`;
            if (!dist.has(newKey) || dist.get(newKey)! > newCost) {
                dist.set(newKey, newCost);
                pq.push([newCost, i, j, nextTime]);
            }
        }
    }
    return -1;
}

