import heapq

def solve(m: int, n: int, waitCost: list[list[int]]) -> int:
    heap = [(1, 0, 0, 0)]
    dist = {}
    dist_key = "0_0_0"
    dist[dist_key] = 1

    while heap:
        current_cost, i, j, t = heapq.heappop(heap)
        key = f"{i}_{j}_{t}"
        if i == m - 1 and j == n - 1:
            return current_cost
        if dist.get(key, float('inf')) < current_cost:
            continue
        next_time = t + 1
        if next_time % 2 == 1:
            # Move right or down
            if j + 1 < n:
                new_i, new_j = i, j + 1
                new_cost = current_cost + (new_i + 1) * (new_j + 1)
                new_key = f"{new_i}_{new_j}_{next_time}"
                if new_key not in dist or dist[new_key] > new_cost:
                    dist[new_key] = new_cost
                    heapq.heappush(heap, (new_cost, new_i, new_j, next_time))
            if i + 1 < m:
                new_i, new_j = i + 1, j
                new_cost = current_cost + (new_i + 1) * (new_j + 1)
                new_key = f"{new_i}_{new_j}_{next_time}"
